const helmet = require('helmet');
const rateLimit = require('express-rate-limit');
const cors = require('cors');
const { query, validationResult } = require('express-validator');

const app = express();

// --- Security Middleware ---

// Set security HTTP headers (X-Content-Type-Options, X-Frame-Options, CSP, etc.)
app.use(helmet());

// Explicit CORS configuration — restrict to known origins in production
app.use(cors({
  origin: process.env.ALLOWED_ORIGINS?.split(',') || 'http://localhost:3000',
  methods: ['GET'],
}));

// Rate limiting to prevent abuse
const limiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 100,                  // limit each IP to 100 requests per window
  standardHeaders: true,
  legacyHeaders: false,
  message: { error: 'Too many requests, please try again later.' },
});
app.use(limiter);

// Body parsing with size limits (for future POST/PUT routes)
app.use(express.json({ limit: '10kb' }));
app.use(express.urlencoded({ extended: false, limit: '10kb' }));

// Disable X-Powered-By to reduce fingerprinting (helmet does this too)
app.disable('x-powered-by');

// --- Routes ---

