  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 100,                  // limit each IP to 100 requests per window
  standardHeaders: true,
  legacyHeaders: false,
  message: { error: 'Too many requests, please try again later.' },
});
app.use(limiter);

// Parse JSON bodies with a size limit to prevent large-payload attacks
app.use(express.json({ limit: '10kb' }));
app.use(express.urlencoded({ extended: false, limit: '10kb' }));

// Disable the X-Powered-By header (info leakage)
app.disable('x-powered-by');

// --- Routes ---

app.get('/health', (_req, res) => {
  res.json({ status: 'ok', timestamp: new Date().toISOString() });
});

app.get('/users', (req, res) => {
  // Validate optional query parameters
  const allowedParams = ['id', 'name'];
  const unknownParams = Object.keys(req.query).filter(
    (key) => !allowedParams.includes(key)
  );

  if (unknownParams.length > 0) {
    return res.status(400).json({
      error: 'Invalid query parameters',
      invalid: unknownParams,
    });
  }

  // If an id filter is provided, validate it is a positive integer
  if (req.query.id !== undefined) {
    const id = Number(req.query.id);
    if (!Number.isInteger(id) || id <= 0) {
      return res.status(400).json({ error: 'Parameter "id" must be a positive integer.' });
    }
  }

  // If a name filter is provided, validate it is alphanumeric (no injection)
  if (req.query.name !== undefined) {
    if (typeof req.query.name !== 'string' || !/^[a-zA-Z\s'-]{1,100}$/.test(req.query.name)) {
      return res.status(400).json({ error: 'Parameter "name" contains invalid characters.' });
    }
  }

  const users = [
    { id: 1, name: 'Alice', email: 'alice@example.com' },
    { id: 2, name: 'Bob', email: 'bob@example.com' },
  ];

  res.json(users);
});

// --- 404 Handler ---
app.use((_req, res) => {
  res.status(404).json({ error: 'Not found' });
});

// --- Global Error Handler ---
// Catches unhandled errors without leaking stack traces to clients
app.use((err, _req, res, _next) => {
  console.error('Unhandled error:', err.message);
  res.status(err.status || 500).json({
    error: process.env.NODE_ENV === 'production'
      ? 'Internal server error'
      : err.message,
  });
});

// --- Start Server ---
if (require.main === module) {
  app.listen(PORT, () => {
    console.log(`Server running on port ${PORT}`);
  });
}

module.exports = app;

